<span class="line"><span style="color:#89B4FA;font-style:italic;">        assert_eq!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">result</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;ls -la&quot;</span><span style="color:#9399B2;">);</span></span>
